import{_ as r,o as a,c as e,ae as l}from"./chunks/framework.DrYEjkpc.js";const c=JSON.parse('{"title":"SkillRet","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillret.md","filePath":"radar/tech-skillret.md"}'),i={name:"radar/tech-skillret.md"};function o(d,t,h,n,s,u){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="skillret" tabindex="-1">SkillRet <a class="header-anchor" href="#skillret" aria-label="Permalink to &quot;SkillRet&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 评测 / Skill 召回 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.47</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>Skill 检索的大规模 benchmark</strong> —— 17,810 公共 Skill + 63K 训练 + 5K 评测查询。比最强基线 <strong>NDCG@10 +13.1</strong>，比最强 off-the-shelf 检索器 +16.9。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li><li>论文 + benchmark 数据集</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2605.05726" target="_blank" rel="noreferrer">arXiv 2605.05726</a></li><li>标题：<em>SkillRet: A Large-Scale Benchmark for Skill Retrieval in LLM Agents</em></li><li>提交：2026-05-07</li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="数据规模" tabindex="-1">数据规模 <a class="header-anchor" href="#数据规模" aria-label="Permalink to &quot;数据规模&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项</th><th>数量</th></tr></thead><tbody><tr><td>公共 Skill</td><td><strong>17,810</strong></td></tr><tr><td>训练样本</td><td><strong>63,259</strong></td></tr><tr><td>评测查询</td><td><strong>4,997</strong></td></tr></tbody></table><p>是 Skill 检索领域<strong>当前最大规模</strong>的 benchmark。</p><h3 id="关键数字" tabindex="-1">关键数字 <a class="header-anchor" href="#关键数字" aria-label="Permalink to &quot;关键数字&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比项</th><th>提升</th></tr></thead><tbody><tr><td>比最强 prior retriever</td><td><strong>NDCG@10 +13.1</strong></td></tr><tr><td>比最强 off-the-shelf retriever</td><td><strong>NDCG@10 +16.9</strong></td></tr></tbody></table><h3 id="与-skillrouter-的关系" tabindex="-1">与 SkillRouter 的关系 <a class="header-anchor" href="#与-skillrouter-的关系" aria-label="Permalink to &quot;与 SkillRouter 的关系&quot;">​</a></h3><ul><li><strong>SkillRouter</strong> 提供路由方法论与轻量模型架构</li><li><strong>SkillRet</strong> 提供 SkillRouter 缺失的<strong>标准化评测套件</strong></li></ul><p>两者搭配使用，业界首次有了完整的&quot;召回方法 + 召回评测&quot;组合。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>标准化 Skill 检索评测</li><li>17,810 Skill 的公共数据集</li><li>NDCG@10 等多种检索指标</li></ul><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>召回算法的迭代评测</li><li>不同检索器的横向对比</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>数据集质量取决于 17K Skill 的来源覆盖</li><li>学术阶段，未见工业 retriever 提交</li><li>不评测路由后的 task success rate（只评测检索本身）</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文 + 数据集发布</td></tr><tr><td>创新性</td><td>0.55</td><td>填补 Skill 检索 benchmark 的空白</td></tr><tr><td>落地程度</td><td>0.40</td><td>学术阶段</td></tr><tr><td>生态活跃度</td><td>0.35</td><td>较新（2026-05）</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.47</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2605.05726" target="_blank" rel="noreferrer">SkillRet 论文</a></li></ul>',34)])])}const b=r(i,[["render",o]]);export{c as __pageData,b as default};
